#ifndef TOP_K_TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H
#define TOP_K_TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H

#include <cstdint>
#include <cuda_runtime.h>

#define VOCAB_SIZE_QWEN3 151936

// Fast path kernel launcher.
// Supports:
//  - Per-row top-k with 1..64 and any top-p (including (0,1))
//  - No-topk only when top_p<=0 (argmax) or top_p>=1 (full multinomial)
void top_k_top_p_sampling_from_probs_v151936_launcher(
    const float* probs,          // [B, V]
    const int32_t* top_k,         // [B]
    const float* top_p,           // [B]
    int64_t* samples,             // [B]
    int64_t batch_size,
    cudaStream_t stream);

#endif  // TOP_K_TOP_P_SAMPLING_FROM_PROBS_V151936_KERNEL_H

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <limits>

#ifndef __CUDA_ARCH__
#define __CUDA_ARCH__ 0
#endif

static __device__ __forceinline__ float warp_reduce_sum(float v) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) v += __shfl_down_sync(0xffffffff, v, offset);
  return v;
}
static __device__ __forceinline__ float warp_reduce_max(float v) {
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) v = fmaxf(v, __shfl_down_sync(0xffffffff, v, offset));
  return v;
}

template<int BLOCK>
static __device__ __forceinline__ float block_reduce_sum(float v) {
  __shared__ float sh[32]; // up to 1024 threads -> 32 warps
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;
  v = warp_reduce_sum(v);
  if (lane == 0) sh[wid] = v;
  __syncthreads();
  v = (threadIdx.x < (BLOCK >> 5)) ? sh[lane] : 0.0f;
  if (wid == 0) v = warp_reduce_sum(v);
  return v;
}

template<int BLOCK>
static __device__ __forceinline__ float block_reduce_max(float v) {
  __shared__ float sh[32];
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;
  v = warp_reduce_max(v);
  if (lane == 0) sh[wid] = v;
  __syncthreads();
  v = (threadIdx.x < (BLOCK >> 5)) ? sh[lane] : -CUDART_INF_F;
  if (wid == 0) v = warp_reduce_max(v);
  return v;
}

// RNG
static __device__ __forceinline__ uint32_t splitmix32(uint32_t x) {
  x += 0x9e3779b9u;
  x = (x ^ (x >> 16)) * 0x85ebca6bu;
  x = (x ^ (x >> 13)) * 0xc2b2ae35u;
  x ^= (x >> 16);
  return x;
}

struct XorShift32 {
  uint32_t state;
  __device__ explicit XorShift32(uint32_t seed) : state(seed ? seed : 1u) {}
  __device__ __forceinline__ uint32_t next_u32() {
    uint32_t x = state;
    x ^= x << 13;
    x ^= x >> 17;
    x ^= x << 5;
    state = x;
    return x;
  }
  __device__ __forceinline__ float next_uniform_open01() {
    // (0,1), ~24-bit mantissa
    uint32_t r = next_u32();
    return (float)((r >> 8) + 1u) * (1.0f / 16777217.0f);
  }
};

template<int KSMALL>
struct TopKSmall {
  float v[KSMALL];
  int   i[KSMALL];

  __device__ __forceinline__ void init() {
    #pragma unroll
    for (int t = 0; t < KSMALL; ++t) { v[t] = -CUDART_INF_F; i[t] = -1; }
  }

  __device__ __forceinline__ void insert(float val, int idx) {
    if (val <= v[KSMALL-1]) return;
    int p = KSMALL - 1;
    v[p] = val; i[p] = idx;
    #pragma unroll
    for (int j = KSMALL - 2; j >= 0; --j) {
      if (v[j] >= v[j+1]) break;
      float tv = v[j]; v[j] = v[j+1]; v[j+1] = tv;
      int   ti = i[j]; i[j] = i[j+1]; i[j+1] = ti;
    }
  }
};

template<int BLOCK>
__device__ __forceinline__ int block_argmax_full(const float* __restrict__ rowp) {
  float local_max = -CUDART_INF_F;
  int local_idx = 0;
  for (int t = threadIdx.x; t < VOCAB_SIZE_QWEN3; t += BLOCK) {
    float v = rowp[t];
    if (v > local_max) { local_max = v; local_idx = t; }
  }
  float maxv = block_reduce_max<BLOCK>(local_max);
  maxv = __shfl_sync(0xffffffff, maxv, 0);

  __shared__ int best;
  if (threadIdx.x == 0) best = INT_MAX;
  __syncthreads();
  if (local_max == maxv) atomicMin(&best, local_idx);
  __syncthreads();
  return best;
}

template<int BLOCK>
__device__ __forceinline__ int block_multinomial_full(const float* __restrict__ rowp, XorShift32& rng) {
  float local_sum = 0.0f;
  for (int t = threadIdx.x; t < VOCAB_SIZE_QWEN3; t += BLOCK) local_sum += rowp[t];
  float sum = block_reduce_sum<BLOCK>(local_sum);
  sum = __shfl_sync(0xffffffff, sum, 0);

  float u = 0.0f;
  if (threadIdx.x == 0) u = rng.next_uniform_open01() * sum;
  u = __shfl_sync(0xffffffff, u, 0);

  int picked = VOCAB_SIZE_QWEN3 - 1;
  if (threadIdx.x == 0) {
    float acc = 0.0f;
    for (int t = 0; t < VOCAB_SIZE_QWEN3; ++t) {
      acc += rowp[t];
      if (u < acc) { picked = t; break; }
    }
  }
  picked = __shfl_sync(0xffffffff, picked, 0);
  return picked;
}

template<int BLOCK, int KSMALL>
__global__ void mixed_kernel_k64(
    const float* __restrict__ probs,
    const int32_t* __restrict__ top_k,
    const float* __restrict__ top_p,
    int64_t* __restrict__ out,
    int64_t B,
    uint64_t seed_base)
{
  int64_t row = (int64_t)blockIdx.x;
  if (row >= B) return;

  const float* __restrict__ rowp = probs + row * (int64_t)VOCAB_SIZE_QWEN3;

  int k = (int)top_k[row];
  float p = top_p[row];

  if (k < 0) k = 0;
  if (k > VOCAB_SIZE_QWEN3) k = VOCAB_SIZE_QWEN3;
  const bool apply_topk = (k > 0 && k < VOCAB_SIZE_QWEN3);

  uint32_t seed = splitmix32((uint32_t)row ^ (uint32_t)seed_base ^ (uint32_t)(seed_base >> 32));
  XorShift32 rng(seed);

  // No top-k: exact only for p<=0 (argmax) and p>=1 (full multinomial)
  if (!apply_topk) {
    if (p <= 0.0f) {
      int best = block_argmax_full<BLOCK>(rowp);
      if (threadIdx.x == 0) out[row] = (int64_t)best;
      return;
    }
    // For p in (0,1): host guarantees we won't be here.
    int picked = block_multinomial_full<BLOCK>(rowp, rng);
    if (threadIdx.x == 0) out[row] = (int64_t)picked;
    return;
  }

  // apply top-k, host ensures k<=64; still clamp for safety
  if (k > KSMALL) k = KSMALL;

  TopKSmall<KSMALL> tk;
  tk.init();
  for (int t = threadIdx.x; t < VOCAB_SIZE_QWEN3; t += BLOCK) {
    tk.insert(rowp[t], t);
  }

  // shared staging (size: BLOCK*KSMALL)
  __shared__ float shv[BLOCK * KSMALL];
  __shared__ int   shi[BLOCK * KSMALL];
  #pragma unroll
  for (int j = 0; j < KSMALL; ++j) {
    shv[threadIdx.x * KSMALL + j] = tk.v[j];
    shi[threadIdx.x * KSMALL + j] = tk.i[j];
  }
  __syncthreads();

  __shared__ float out_v[KSMALL];
  __shared__ int   out_i[KSMALL];

  if (threadIdx.x == 0) {
    TopKSmall<KSMALL> merged;
    merged.init();
    for (int t = 0; t < BLOCK * KSMALL; ++t) merged.insert(shv[t], shi[t]);
    #pragma unroll
    for (int j = 0; j < KSMALL; ++j) { out_v[j] = merged.v[j]; out_i[j] = merged.i[j]; }
  }
  __syncthreads();

  if (p <= 0.0f) {
    if (threadIdx.x == 0) out[row] = (int64_t)out_i[0];
    return;
  }

  int keep_n = k;
  if (p < 1.0f) {
    int kn_local = k;
    if (threadIdx.x == 0) {
      // Match reference nucleus semantics with "shifted remove":
      // keep j if j==0 OR cdf(j-1) <= p
      float cdf_prev = 0.0f;
      int kn = 0;
      for (int j = 0; j < k; ++j) {
        if (j == 0 || cdf_prev <= p) {
          ++kn;
        } else {
          break;
        }
        cdf_prev += out_v[j];
      }
      if (kn < 1) kn = 1;
      kn_local = kn;
    }
    keep_n = __shfl_sync(0xffffffff, kn_local, 0);
    __syncthreads();
  }

  float local_sum = 0.0f;
  for (int j = threadIdx.x; j < keep_n; j += BLOCK) local_sum += out_v[j];
  float sum_keep = block_reduce_sum<BLOCK>(local_sum);
  sum_keep = __shfl_sync(0xffffffff, sum_keep, 0);

  float u = 0.0f;
  if (threadIdx.x == 0) u = rng.next_uniform_open01() * sum_keep;
  u = __shfl_sync(0xffffffff, u, 0);

  if (threadIdx.x == 0) {
    float acc = 0.0f;
    int picked = out_i[keep_n - 1];
    for (int j = 0; j < keep_n; ++j) {
      acc += out_v[j];
      if (u < acc) { picked = out_i[j]; break; }
    }
    out[row] = (int64_t)picked;
  }
}

void top_k_top_p_sampling_from_probs_v151936_launcher(
    const float* probs,
    const int32_t* top_k,
    const float* top_p,
    int64_t* samples,
    int64_t batch_size,
    cudaStream_t stream)
{
  if (batch_size <= 0) return;

  constexpr int BLOCK = 256;
  constexpr int KSMALL = 64;

  dim3 grid((uint32_t)batch_size);
  dim3 block(BLOCK);

  uint64_t seed_base =
      (uint64_t)(uintptr_t)probs ^
      (uint64_t)(uintptr_t)samples ^
      (uint64_t)batch_size ^
      0x9e3779b97f4a7c15ull;

  mixed_kernel_k64<BLOCK, KSMALL><<<grid, block, 0, stream>>>(
      probs, top_k, top_p, samples, batch_size, seed_base);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>

#include <cuda_runtime.h>
#include <stdexcept>
#include <string>

#include "kernel.h"

static inline void cuda_check(cudaError_t err, const char* msg) {
  if (err != cudaSuccess) {
    throw std::runtime_error(std::string(msg) + ": " + cudaGetErrorString(err));
  }
}

static void check_cuda_tensor(const torch::Tensor& t, const char* name) {
  if (!t.defined()) throw std::runtime_error(std::string(name) + " must be a defined tensor.");
  if (!t.device().is_cuda()) throw std::runtime_error(std::string(name) + " must be a CUDA tensor.");
}

static torch::Tensor fallback_reference(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p) {
  // NOTE: This is slow but correct; used only when fast-path constraints are not met.
  auto B = probs.size(0);
  auto V = probs.size(1);

  auto samples = torch::empty({B}, torch::TensorOptions().device(probs.device()).dtype(torch::kInt64));

  for (int64_t i = 0; i < B; ++i) {
    auto row = probs[i];
    int64_t k = (int64_t)top_k[i].item<int32_t>();
    float p = top_p[i].item<float>();

    if (0 < k && k < V) {
      auto sorted = row.sort(/*dim=*/0, /*descending=*/true);
      auto idx_sorted = std::get<1>(sorted);
      auto keep_idx_k = idx_sorted.slice(/*dim=*/0, /*start=*/0, /*end=*/k);
      auto filtered_k = torch::zeros_like(row);
      filtered_k.index_put_({keep_idx_k}, row.index({keep_idx_k}));
      row = filtered_k / filtered_k.sum();
    }

    if (p <= 0.0f) {
      samples[i] = std::get<1>(row.max(/*dim=*/0)).to(torch::kInt64);
      continue;
    }

    if (p < 1.0f) {
      auto sorted = row.sort(/*dim=*/0, /*descending=*/true);
      auto vals = std::get<0>(sorted);
      auto idx  = std::get<1>(sorted);
      auto cdf = vals.cumsum(0);
      auto to_remove = cdf > p;
      if (V > 1) {
        auto shifted = to_remove.slice(0, 0, V - 1).clone();
        to_remove.slice(0, 1, V).copy_(shifted);
        to_remove.index_put_({0}, false);
      } else {
        to_remove.index_put_({0}, false);
      }
      auto keep_idx_p = idx.index({~to_remove});
      auto filtered_p = torch::zeros_like(row);
      filtered_p.index_put_({keep_idx_p}, row.index({keep_idx_p}));
      row = filtered_p / filtered_p.sum();
    }

    auto sampled = torch::multinomial(row, /*num_samples=*/1, /*replacement=*/true);
    samples[i] = sampled.squeeze(0).to(torch::kInt64);
  }
  return samples;
}

static torch::Tensor run_impl(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p) {
  check_cuda_tensor(probs, "probs");
  check_cuda_tensor(top_k, "top_k");
  check_cuda_tensor(top_p, "top_p");

  if (probs.dtype() != torch::kFloat32) throw std::runtime_error("probs must be float32.");
  if (top_k.dtype() != torch::kInt32) throw std::runtime_error("top_k must be int32.");
  if (top_p.dtype() != torch::kFloat32) throw std::runtime_error("top_p must be float32.");

  if (probs.dim() != 2) throw std::runtime_error("probs must be 2D [batch_size, vocab_size].");
  if (top_k.dim() != 1) throw std::runtime_error("top_k must be 1D [batch_size].");
  if (top_p.dim() != 1) throw std::runtime_error("top_p must be 1D [batch_size].");

  const int64_t B = probs.size(0);
  const int64_t V = probs.size(1);
  if (V != VOCAB_SIZE_QWEN3) throw std::runtime_error("vocab_size must be 151936.");
  if (top_k.size(0) != B) throw std::runtime_error("top_k must have shape [batch_size].");
  if (top_p.size(0) != B) throw std::runtime_error("top_p must have shape [batch_size].");

  if (!probs.is_contiguous()) probs = probs.contiguous();
  if (!top_k.is_contiguous()) top_k = top_k.contiguous();
  if (!top_p.is_contiguous()) top_p = top_p.contiguous();

  // Fast-path eligibility:
  // - If apply_topk: require k<=64
  // - If no topk (k<=0 or k>=V): allow only p<=0 or p>=1
  bool use_fast = true;
  auto topk_cpu = top_k.to(torch::kCPU, /*non_blocking=*/false);
  auto topp_cpu = top_p.to(torch::kCPU, /*non_blocking=*/false);

  const int32_t* hk = topk_cpu.data_ptr<int32_t>();
  const float*  hp = topp_cpu.data_ptr<float>();

  for (int64_t i = 0; i < B; ++i) {
    int32_t k = hk[i];
    float p = hp[i];
    bool apply_topk = (k > 0 && k < (int32_t)V);
    if (apply_topk && k > 64) { use_fast = false; break; }
    if (!apply_topk && (p > 0.0f && p < 1.0f)) { use_fast = false; break; }
  }

  c10::cuda::CUDAGuard device_guard(probs.device());

  if (!use_fast) {
    return fallback_reference(probs, top_k, top_p);
  }

  auto samples = torch::empty({B}, torch::TensorOptions().device(probs.device()).dtype(torch::kInt64));
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(probs.device().index());

  top_k_top_p_sampling_from_probs_v151936_launcher(
      probs.data_ptr<float>(),
      top_k.data_ptr<int32_t>(),
      top_p.data_ptr<float>(),
      samples.data_ptr<int64_t>(),
      B,
      stream);

  cuda_check(cudaGetLastError(), "Kernel launch failed");
  // Avoid a hard sync in real deployments; kept to ensure correctness in this harness.
  cuda_check(cudaStreamSynchronize(stream), "Stream synchronize failed");
  return samples;
}

torch::Tensor run(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p) {
  return run_impl(probs, top_k, top_p);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        py::arg("probs"), py::arg("top_k"), py::arg("top_p"));
}
